mapper.select:
select r.id, r.subject_id, r.device_id, s.subject_name, s.subject_age,
d.device_name, r.collection_time, r.sample_rate, r.status, r.remark
from bcg_data_record r
left join bcg_subject s on r.subject_id = s.id
left join bcg_device d on r.device_id = d.id

     and r.subject_id = #{subjectId} 
     and r.status = #{status} 

        and s.subject_name like concat('%', #{subjectName}, '%')


        and r.collection_time >= #{beginTime}


        and r.collection_time <= #{endTime}


order by r.collection_time desc

SELECT r.id AS id, r.subject_id AS subjectId, s.subject_name AS subjectName, r.collection_time AS collectionTime, r.report_status AS reportStatus, r.report_time AS reportTime, r.report_file_url AS reportFileUrl FROM bcg_data_record r LEFT JOIN bcg_subject s ON r.subject_id = s.id
r.status = 1
AND r.subject_id = #{subjectId}
AND DATE_FORMAT(r.report_time,'%Y-%m-%d') >= #{beginTime}
AND DATE_FORMAT(r.report_time,'%Y-%m-%d') <= #{endTime}
ORDER BY r.collection_time DESC
